.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    line-height: 1.4;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #1264a3;
}

.send-btn {
    padding: 8px 18px;
    background-color: #1264a3;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    font-size: 0.88rem;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-btn:hover:not(:disabled) {
    background-color: #0e4f82;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

