@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        <h2># @ChannelName</h2>
        @if (!string.IsNullOrEmpty(ChannelDescription))
        {
            <p class="area-description">@ChannelDescription</p>
        }
    </div>

    <div class="message-list" @ref="_scrollContainer">
        @if (_isLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }

        @foreach (var message in Messages)
        {
            <MessageBubble Message="message"
                           ReplyCount="GetReplyCount(message.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")" OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }

    private ElementReference _scrollContainer;
    private IJSObjectReference? _module;
    private DotNetObjectReference<MessageArea>? _dotNetRef;
    private bool _isLoadingMore;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Chat/MessageArea.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initScrollDetection", _scrollContainer, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (_isLoadingMore) return;
        _isLoadingMore = true;
        StateHasChanged();
        await OnLoadMore.InvokeAsync();
        _isLoadingMore = false;
        StateHasChanged();
    }

    private int GetReplyCount(int messageId)
    {
        return ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId)?.ReplyCount ?? 0;
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #1a1a2e;
}

.area-description {
    margin: 2px 0 0;
    font-size: 0.82rem;
    color: #777;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    font-size: 0.82rem;
    color: #999;
}

let observer = null;
let sentinel = null;

export function initScrollDetection(scrollContainer, dotNetRef) {
    sentinel = document.createElement('div');
    sentinel.style.height = '1px';
    scrollContainer.prepend(sentinel);

    observer = new IntersectionObserver(
        (entries) => {
            if (entries[0].isIntersecting) {
                dotNetRef.invokeMethodAsync('OnScrolledToTop');
            }
        },
        { root: scrollContainer, threshold: 1.0 }
    );
    observer.observe(sentinel);

    // Start scrolled to the bottom
    scrollContainer.scrollTop = scrollContainer.scrollHeight;
}

export function dispose() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
    if (sentinel) {
        sentinel.remove();
        sentinel = null;
    }
}

