@page "/chat"
@attribute [StreamRendering]
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-column">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-column" style="@MainColumnStyle">
        @if (_activeChannel is not null)
        {
            <MessageArea ChannelName="@_activeChannel.Name"
                         ChannelDescription="@_activeChannel.Description"
                         Messages="_messages"
                         ThreadSummaries="_threadSummaries"
                         OnLoadMore="LoadOlderMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="thread-column">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private int _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];
    private bool _hasMoreMessages = true;

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    private string MainColumnStyle =>
        _threadOpen ? "flex: 55;" : "flex: 80;";

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _hasMoreMessages = true;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        BuildThreadSummaries();

        CloseThread();
        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadOlderMessages()
    {
        if (!_hasMoreMessages || _activeChannel is null) return;

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _messages.Count, PageSize);
        if (older.Count < PageSize)
        {
            _hasMoreMessages = false;
        }

        _messages.InsertRange(0, older);
        BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;

        var message = await ChatService.SendMessageAsync(_activeChannelId, content, null);
        _messages.Add(message);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the reaction in whichever list contains the message
        UpdateReactionInList(_messages, args.MessageId, args.Emoji);
        UpdateReactionInList(_threadReplies, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionInList(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var reaction = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (reaction is not null)
        {
            reaction.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(
            _activeChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update thread summary count
        var summary = _threadSummaries.FirstOrDefault(
            t => t.RootMessageId == _threadRootMessage.Id);
        if (summary is not null)
        {
            var i = _threadSummaries.IndexOf(summary);
            _threadSummaries[i] = summary with
            {
                ReplyCount = summary.ReplyCount + 1,
                LastReplyAt = DateTime.UtcNow
            };
        }
        else
        {
            _threadSummaries.Add(new ThreadSummary(
                _threadRootMessage.Id, 1, DateTime.UtcNow));
        }
    }

    private void BuildThreadSummaries()
    {
        // Derive thread summaries from messages that are replies
        var replies = _messages.Where(m => m.ReplyToId.HasValue).ToList();
        _threadSummaries = replies
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
    }
}

